export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method !== 'GET') return res.status(405).json({ error: 'Méthode non autorisée' })

  const TOUTES_CATEGORIES = ['Littérature', 'Philosophie', 'Sciences', 'Histoire', 'Vie quotidienne', 'Art', 'Gastronomie', 'Nature', 'Politique', 'Sport']
  const today = new Date().toISOString().split('T')[0]
  const debut = new Date('2024-01-01').getTime()
  const joursEcoules = Math.floor((new Date().getTime() - debut) / (1000 * 60 * 60 * 24))

  const catsShuffle = [...TOUTES_CATEGORIES].sort(() => (Math.sin(joursEcoules) * 10000) % 1 - 0.5)
  const troisCats = catsShuffle.slice(0, 3)

  const mots = troisCats.map((cat, i) => {
    const motsCategorie = BANQUE_MOTS.filter(m => m.theme === cat && m.type === 'mot')
    if (motsCategorie.length === 0) return { ...BANQUE_MOTS[i % BANQUE_MOTS.length], date: today }
    const idx = (joursEcoules + i * 7) % motsCategorie.length
    return { ...motsCategorie[idx], date: today }
  })

  const expressions = BANQUE_MOTS.filter(m => m.type === 'expression')
  const expr = expressions[joursEcoules % expressions.length]
  mots[2] = { ...expr, date: today }

  return res.status(200).json(mots)
}
